SELECT(SUM(?numGames) AS ?totalGames) WHERE {
  VALUES ?seriesLabel {
    "1982 National League Championship Series" @en "2006 National League Championship Series" @en "2011 World Series" @en "2013 National League Championship Series" @en "2011 National League Championship Series" @en
  }
  ?series rdfs:label ?seriesLabel .
  ?series wdt:P710 wd:Q166474 .
  ?series wdt:P2633 ?numGames .
}

SELECT ?team(COUNT(*) AS ?count) WHERE {
  VALUES ?event {
    wd:Q1646964 wd:Q636022 wd:Q18076452 wd:Q106684402 wd:Q33112992
  }
  VALUES ?team {
    wd:Q1513127 wd:Q586949
  }
  ?event wdt:P1346 ?team
}
GROUP BY ?team

SELECT ?series ?attendance WHERE {
  ?series wdt:P1923 wd:Q334634 ; wdt:P1923 wd:Q650840 ; wdt:P1110 ?attendance .
}
ORDER BY DESC(xsd:integer(REPLACE(?attendance , "," , "")))
LIMIT 1
OFFSET 1

SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  VALUES ?championship {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?game wdt:P361 ?championship ; wdt:P1535 wd:Q213959 ; wdt:P1083 ?attendance .
  FILTER(xsd:integer(?attendance) > 0)
}
LIMIT 10

SELECT(MAX(?margin) AS ?maxMargin) WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?game wdt:P361 ?series .
  ?game p:P710 ?ps1 .
  ?ps1 ps:P710 wd:Q213959 ; pq:P1351 ?redsoxScore .
  ?game p:P710 ?ps2 .
  ?ps2 ps:P710 ?opponent ; pq:P1351 ?opponentScore .
  FILTER(?opponent != wd:Q213959)
  BIND(ABS(?redsoxScore - ?opponentScore) AS ?margin)
}

SELECT((MAX(?races) - MIN(?races)) AS ?difference) WHERE {
  ?season wdt:P3450 wd:Q1084 .
  ?season wdt:P1346 wd:Q9673 .
  ?season wdt:P1346 wd:Q172721 .
  ?season wdt:P729 ?races .
}

SELECT((?wsWins - ?nlcsWins) AS ?difference) WHERE {
  {
