      ?wsGame wdt:P361 wd:Q193344 ; wdt:P276 wd:Q6046445 ; wdt:P1346 wd:Q492 .
    }
  }
  {
    SELECT(COUNT(?nlcsGame) AS ?nlcsWins) WHERE {
      ?nlcsGame wdt:P361 wd:Q1721059 ; wdt:P276 wd:Q6046445 ; wdt:P1346 wd:Q492 .
    }
  }
}

SELECT(SUM(xsd:integer(?games)) AS ?total) WHERE {
  {
    ?series wdt:P31 wd:Q7255725 ; wdt:P710 wd:Q504309 ; wdt:P585 ?date ; wdt:P5088 ?games .
    FILTER((YEAR(?date) = 1982) ||(YEAR(?date) = 2006) ||(YEAR(?date) = 2011) ||(YEAR(?date) = 2013))
  } UNION {
    ?series wdt:P31 wd:Q208606 ; wdt:P710 wd:Q504309 ; wdt:P585 ?date ; wdt:P5088 ?games .
    FILTER(YEAR(?date) = 2011)
  }
}

