      ?season wdt:P31 wd:Q171879 ; wdt:P1346 wd:Q9671 ; wdt:P585 ?time .
    }
    ORDER BY ASC(?time)
    LIMIT 1
  } UNION {
    SELECT ?season WHERE {
      ?season wdt:P31 wd:Q171879 ; wdt:P1346 wd:Q9671 ; wdt:P585 ?time .
    }
    ORDER BY DESC(?time)
    LIMIT 1
  }
  ?season wdt:P1113 ?numRaces .
}

SELECT(SUM(xsd:integer(?wins)) AS ?total_games) WHERE {
  ?series wdt:P31 wd:Q1363275 ; wdt:P1923 wd:Q334634 ; wdt:P1923 wd:Q650840 ; wdt:P585 ?date .
  {
    ?series p:P1366 / ps:P1366 ?team ; p:P1366 / pq:P1267 ?wins .
  } UNION {
    ?series p:P1367 / ps:P1367 ?team ; p:P1367 / pq:P1267 ?wins .
  }
  VALUES ?team {
    wd:Q334634 wd:Q650840
  }
  BIND(xsd:integer(SUBSTR(STR(?date) , 1 , 4)) AS ?year)
  FILTER(?year >= 1978 && ?year <= 2009)
}

SELECT((MAX(YEAR(?date)) - MIN(YEAR(?date))) AS ?difference) WHERE {
  {
    ?edition wdt:P1346 wd:Q334634 ; wdt:P1344 wd:Q650840 ; wdt:P585 ?date
  } UNION {
    ?edition wdt:P1346 wd:Q650840 ; wdt:P1344 wd:Q334634 ; wdt:P585 ?date
  }
}

SELECT(COUNT(?race) AS ?count) WHERE {
  ?race wdt:P31 wd:Q7965 ; wdt:P585 ?date ; wdt:P3764 wd:Q9673 .
  FILTER(YEAR(?date) >= 2016)
}
